#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
using namespace std;
CI MAXN=1e5+5;
int n,p[MAXN],l[MAXN],r[MAXN],A[MAXN],B[MAXN];
struct NODE
{
	int x,nxt;
}a[MAXN];
bool cmp(NODE a1,NODE a2)
{
    if(a1.x==a2.x)return a1.nxt<a2.nxt;
    return a1.x<a2.x;
}
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%d",&n);
    for(int i=1;i<=n;++i)
	{
		scanf("%d",&a[i].x),a[i].nxt=i;
	}
    a[0].x=0x3f3f3f3f;
	a[n+1].x=-0x3f3f3f3f;
    sort(a+1,a+n+1,cmp);
    for(int i=1;i<=n;++i)
	{
		p[a[i].nxt]=i,l[i]=i-1,r[i]=i+1;
	}
    for(int i=n;i>1;--i)
	{
        int num=p[i],L=l[num],R=r[num];
        int ml=abs(a[num].x-a[L].x);
		int mr=abs(a[num].x-a[R].x);
        if(ml<=mr)
		{
        	A[i]=ml;
			B[i]=a[L].nxt;
		}
        else
		{
        	A[i]=mr;
			B[i]=a[R].nxt;
		} 
        l[R]=L,r[L]=R;
    }
    for(int i=2;i<=n;i++)printf("%d %d\n",A[i],B[i]);
    return false;
}
